module.render:
const def = (v, d) => (v === undefined || v === '') ? d : v;
// Size values land in a style attribute, so strip characters that could break
// out of it. Labels/caption go through markdown instead, so they are untouched.
const cssLen = (v) => String(v || '').replace(/[<>"';]/g, '').trim();

const top = (args.top || '').trim();
// Back-compat: the old x/y label params map to bottom/left.
const bottom = (args.bottom || args.xlabel || '').trim();
const left = (args.left || args.ylabel || '').trim();
const right = (args.right || '').trim();
const imagesize = cssLen(args.imagesize);
const labelsize = cssLen(def(args.labelsize, '0.75em')) || '0.75em';
const captionsize = cssLen(def(args.captionsize, '0.75em')) || '0.75em';
// First body section = the image; OPTIONAL second section (after `<!-- @ -->`)
// = the caption (kept as a section so it can be long / contain commas).
const image = (sections[0] || '').trim();
const caption = (sections[1] || '').trim();

// A "%" image width is taken relative to the slide (applied to the figure area
// so the columns stay adjacent); any other length is applied to the image
// itself; blank keeps the image's natural size.
const isPct = /%$/.test(imagesize);
const areaWidth = (imagesize && isPct) ? imagesize : 'fit-content';
const imgWidth = imagesize ? (isPct ? '100%' : imagesize) : 'auto';

const vars = [
  '--graph-label-size: ' + labelsize,
  '--graph-caption-size: ' + captionsize,
  '--graph-area-width: ' + areaWidth,
  '--graph-img-width: ' + imgWidth
].join('; ');

// Each label/caption is wrapped in a block padded with blank lines so the
// Markdown (and KaTeX) inside it is rendered. Empty fields are omitted, and
// each side's grid cell collapses to zero when its label is absent.
const hlabel = (cls, v) => v ? '<div class="mdp-mod-graph-' + cls + ' mdp-mod-graph-hlabel">\n\n' + v + '\n\n</div>' : '';
const vlabel = (cls, v) => v ? '<div class="mdp-mod-graph-' + cls + ' mdp-mod-graph-vlabel"><div class="mdp-mod-graph-vlabel-rot mdp-mod-graph-' + cls + '-rot">\n\n' + v + '\n\n</div></div>' : '';

const topEl = hlabel('top', top);
const bottomEl = hlabel('bottom', bottom);
const leftEl = vlabel('left', left);
const rightEl = vlabel('right', right);
const img = '<div class="mdp-mod-graph-image">\n\n' + image + '\n\n</div>';
const cap = caption ? '<figcaption class="mdp-mod-graph-caption">\n\n' + caption + '\n\n</figcaption>' : '';

return '\n\n<figure class="mdp-mod-graph" style="' + vars + ';">'
  + '<div class="mdp-mod-graph-area">' + topEl + leftEl + img + rightEl + bottomEl + '</div>'
  + cap
  + '</figure>\n\n';
